  'visa.proc.eyebrow': { de: 'Beratungsablauf',                en: 'Consultation flow' },
  'visa.proc.title.a': { de: 'Vier Phasen.',                   en: 'Four phases.' },
  'visa.proc.title.b': { de: 'Klare Wegweisung.',              en: 'Clear guidance.' },
  'visa.proc.lede':    { de: 'Vom unverbindlichen Erstgespräch bis zur fertigen Antragsmappe — Sie wissen jederzeit, wo Sie stehen.',
                         en: 'From a no-strings first call to the finished application file — you always know where you stand.' },
  'visa.phase':        { de: 'Phase',                          en: 'Phase' },
  'visa.proc.1.t':     { de: 'Eignungsanalyse',                en: 'Eligibility check' },
  'visa.proc.1.d':     { de: '30 Minuten kostenfrei. Wir prüfen Ihre Situation, identifizieren das passende Visum und legen einen realistischen Zeitplan fest.',
                         en: '30 minutes free. We assess your situation, identify the right visa and set a realistic timeline.' },
  'visa.proc.2.t':     { de: 'Dokumenten-Audit',               en: 'Document audit' },
  'visa.proc.2.d':     { de: 'Wir erstellen Ihre persönliche Checkliste und prüfen jedes Dokument auf Form, Übersetzung und Apostille — bevor die Botschaft es sieht.',
                         en: 'We build your personal checklist and review every document for format, translation and apostille — before the embassy sees it.' },
