  'visa.faq.eyebrow':  { de: 'FAQ',                            en: 'FAQ' },
  'visa.faq.title.a':  { de: 'Antworten auf',                  en: 'Answers to' },
  'visa.faq.title.b':  { de: 'häufige Fragen.',                en: 'common questions.' },
  'visa.faq.q1':       { de: 'Wie lange dauert ein Visa-Verfahren typischerweise?', en: 'How long does a visa process typically take?' },
  'visa.faq.a1':       { de: 'Das hängt stark vom Heimatland und der Visa-Art ab. Schengen-Visa werden in 10–15 Werktagen erteilt, nationale Visa für Studium oder Arbeit benötigen meist 6–12 Wochen.',
                         en: 'It depends strongly on your home country and visa type. Schengen visas are issued in 10–15 working days; national visas for studies or work usually take 6–12 weeks.' },
  'visa.faq.q2':       { de: 'Übernehmen Sie eine Erfolgsgarantie?', en: 'Do you offer a success guarantee?' },
  'visa.faq.a2':       { de: 'Eine echte Garantie kann seriös niemand geben — die Entscheidung trifft die Botschaft. Was wir garantieren: vollständige, formgerechte Unterlagen und volle Transparenz über alle Schritte.',
                         en: 'No serious provider can guarantee that — the embassy decides. What we guarantee: complete, properly formatted documents and full transparency at every step.' },
  'visa.faq.q3':       { de: 'In welchen Sprachen beraten Sie?', en: 'Which languages do you advise in?' },
  'visa.faq.a3':       { de: 'Deutsch, Englisch, Hindi, Telugu und Urdu. Bei Bedarf vermitteln wir vereidigte Dolmetscher für weitere Sprachen.',
                         en: 'German, English, Hindi, Telugu and Urdu. On request we arrange sworn interpreters for further languages.' },
  'visa.faq.q4':       { de: 'Was kostet die Beratung?',       en: 'What does the consultation cost?' },
  'visa.faq.a4':       { de: 'Das Erstgespräch (30 Min.) ist kostenfrei. Danach arbeiten wir mit transparenten Festpreisen pro Visa-Kategorie — keine versteckten Stundensätze.',
                         en: 'The first call (30 min) is free. After that we work with transparent flat fees per visa category — no hidden hourly rates.' },
  'visa.faq.q5':       { de: 'Sind Sie eine zugelassene Rechtsberatung?', en: 'Are you a licensed legal advisor?' },
  'visa.faq.a5':       { de: 'Trivar ist Beratungsdienstleister, kein Rechtsanwalt. Für rechtsverbindliche Vertretung arbeiten wir mit kooperierenden Fachanwälten für Migrationsrecht zusammen.',
                         en: 'Trivar is a consultancy, not a law firm. For binding legal representation we partner with specialised immigration lawyers.' },
  'visa.faq.q6':       { de: 'Helfen Sie auch nach der Ankunft in Deutschland?', en: 'Do you also help after arrival in Germany?' },
  'visa.faq.a6':       { de: 'Ja. Wir begleiten bei Anmeldung, Bankkonto, Krankenversicherung, Steuer-ID und Aufenthaltstitel-Verlängerung.',
                         en: 'Yes. We help with city registration, bank account, health insurance, tax ID and residence-permit extensions.' },

  'visa.cta.title.a':  { de: 'Bereit für den',                 en: 'Ready for the' },
  'visa.cta.title.b':  { de: 'nächsten Schritt nach Deutschland?', en: 'next step to Germany?' },
  'visa.cta.body':     { de: 'Buchen Sie Ihr kostenfreies 30-Minuten-Erstgespräch. Wir hören zu, prüfen Ihre Situation und sagen ehrlich, was möglich ist.',
                         en: 'Book your free 30-minute first call. We listen, assess your situation and say honestly what\'s possible.' },
  'visa.cta.btn':      { de: 'Erstgespräch buchen',            en: 'Book first call' },

  // ============ OPPORTUNITY CARD ============
  'oc.eyebrow':        { de: 'Neu seit 2024 · § 20a AufenthG', en: 'New since 2024 · § 20a AufenthG' },
  'oc.title.l1':       { de: 'Deutschland',                    en: 'Germany' },
  'oc.title.l2':       { de: 'ohne Jobangebot.',               en: 'without a job offer.' },
  'oc.title.l3':       { de: '12 Monate Zeit.',                en: '12 months on the clock.' },
  'oc.sub':            { de: 'Die Chancenkarte ist Deutschlands neuer Visumtyp für Fachkräfte aus Drittstaaten: bis zu 12 Monate Aufenthalt zur Arbeitssuche, mit erlaubter Teilzeitarbeit (max. 20 Std./Woche) und Probearbeit. Wir prüfen, ob Sie qualifizieren — und stellen den Antrag mit Ihnen gemeinsam.',
                         en: 'The Opportunity Card is Germany\'s new visa for non-EU skilled workers: up to 12 months residence for job-search, with permitted part-time work (max. 20h/week) and trial employment. We check whether you qualify — and file the application together with you.' },
  'oc.cta1':           { de: '6-Punkte-Check starten',         en: 'Start 6-point check' },
  'oc.cta2':           { de: 'So läuft\'s ab',                 en: 'How it works' },

