  'oc.elig.eyebrow':   { de: 'Eligibility',                    en: 'Eligibility' },
  'oc.elig.title.a':   { de: 'Zwei Wege.',                     en: 'Two routes.' },
  'oc.elig.title.b':   { de: 'Eine Karte.',                    en: 'One card.' },
  'oc.elig.lede':      { de: 'Für die Chancenkarte gibt es zwei Routen — abhängig davon, ob Ihr Abschluss in Deutschland bereits anerkannt ist.',
                         en: 'There are two routes to the Opportunity Card — depending on whether your qualification is already recognised in Germany.' },

  'oc.r1.label':       { de: 'Route 01 · Direkt',              en: 'Route 01 · Direct' },
  'oc.r1.title':       { de: 'Anerkannte Fachkraft',           en: 'Recognised skilled worker' },
  'oc.r1.body':        { de: 'Wenn Ihr ausländischer Abschluss in Deutschland voll anerkannt ist — oder Sie in Deutschland studiert/gelernt haben — qualifizieren Sie sich direkt als Fachkraft. Ohne Punktesystem.',
                         en: 'If your foreign qualification is fully recognised in Germany — or you studied/trained in Germany — you qualify directly as a skilled worker. No points system needed.' },
  'oc.r1.l1':          { de: 'Anerkannter Hochschulabschluss oder Berufsausbildung', en: 'Recognised degree or vocational training' },
  'oc.r1.l2':          { de: 'Finanzieller Nachweis (€1.091/Monat oder €13.092/Jahr)', en: 'Financial proof (€1,091/month or €13,092/year)' },
  'oc.r1.l3':          { de: 'Kein Sprachnachweis zwingend erforderlich', en: 'Language proof not strictly required' },
  'oc.r1.l4':          { de: 'Kein Mindestpunktestand',        en: 'No minimum point threshold' },

  'oc.r2.label':       { de: 'Route 02 · Punktesystem',        en: 'Route 02 · Points system' },
  'oc.r2.title':       { de: 'Mindestens 6 Punkte',            en: 'At least 6 points' },
  'oc.r2.body':        { de: 'Wenn Ihr Abschluss noch nicht anerkannt ist, qualifizieren Sie sich über das Punktesystem. Bewertet werden Ausbildung, Berufserfahrung, Sprache, Alter und Bezüge zu Deutschland.',
                         en: 'If your qualification is not yet recognised, you qualify through the points system. It scores education, work experience, language, age and ties to Germany.' },
  'oc.r2.l1':          { de: 'Im Heimatland staatlich anerkannter Abschluss (≥ 2 Jahre)', en: 'State-recognised qualification at home (≥ 2 years)' },
  'oc.r2.l2':          { de: 'Deutsch A1 oder Englisch B2 (CEFR)', en: 'German A1 or English B2 (CEFR)' },
  'oc.r2.l3':          { de: 'Finanzieller Nachweis (€13.092/Jahr)', en: 'Financial proof (€13,092/year)' },
  'oc.r2.l4':          { de: 'Min. 6 Punkte im Punktesystem',  en: 'Min. 6 points in the system' },

  'oc.note.elig':      { de: '<strong>Wichtig:</strong> Mit der Chancenkarte können Sie bis zu 20 Std./Woche arbeiten und kurze Probebeschäftigungen (max. 2 Wochen) annehmen — sie ersetzt aber keinen vollwertigen Arbeitsvertrag. Sobald Sie eine qualifizierte Stelle finden, wechseln Sie auf einen Aufenthaltstitel zur Erwerbstätigkeit oder eine EU Blue Card.',
                         en: '<strong>Important:</strong> The Opportunity Card lets you work up to 20h/week and take short trial jobs (max. 2 weeks) — but it does not replace a full employment permit. Once you find a qualified position, you transition to a work residence permit or EU Blue Card.' },

