/* ====================== APPLY LANGUAGE ====================== */
function applyLang(lang) {
  document.documentElement.lang = lang;

  // text nodes
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    const entry = I18N[key];
    if (!entry) return;
    const txt = entry[lang];
    if (txt === undefined) return;
    if (txt.includes('<')) el.innerHTML = txt; else el.textContent = txt;
  });

  // placeholders
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    const key = el.getAttribute('data-i18n-ph');
    const entry = I18N[key];
    if (entry && entry[lang]) el.setAttribute('placeholder', entry[lang]);
  });

  // toggle visual state
  document.querySelectorAll('.lang-toggle button').forEach(b => {
    b.classList.toggle('active', b.dataset.lang === lang);
  });

  // re-run calculator translation if it's on the page
  if (typeof recalc === 'function') recalc();
}

/* ====================== INIT ====================== */
(function initLang() {
  let lang = localStorage.getItem('trivar-lang');
  if (!lang) {
    lang = (navigator.language || 'de').toLowerCase().startsWith('de') ? 'de' : 'en';
  }
  window.__trivarLang = lang;

  // wait for DOM
  function go() {
    applyLang(lang);
    document.querySelectorAll('.lang-toggle button').forEach(btn => {
      btn.addEventListener('click', () => {
        const newLang = btn.dataset.lang;
        if (newLang === window.__trivarLang) return;
        window.__trivarLang = newLang;
        localStorage.setItem('trivar-lang', newLang);
        applyLang(newLang);
      });
    });
  }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', go);
  else go();
})();

// expose for calculator
function getLang() { return window.__trivarLang || 'de'; }
function t(key) {
  const entry = I18N[key];
  if (!entry) return key;
  return entry[getLang()] || entry.de || key;
}
